// // This module implements a 20-bit synchronous down counter with asynchronous reset. The counter decrements its value on the negative edge of the clock signal when the enable signal is high. If the reset signal is high, the counter resets to zero asynchronously.
module sync_up_counter_20bit(
    input clk,
    input rst,
    input en,
    output reg [19:0] count
);

always @(posedge clk)
    if (rst)
        count <= 20'b00000000000000000000;
    else if (en)
        count <= count + 1;

endmodule
